```mathematica
ExtractHiddenText[stego_Image, secret_String] := Module[
  {stegoBlocks, CVZ, mask, inverseMask, coefficients, block, Blocks, Bits, 
  extractedCVZ, byteGroups, byteValues, decodedText},

  (* Разбиение стего-изображения на блоки 8x8 *)
  stegoBlocks = ImagePartition[stego, {8, 8}];

  (* Инициализация масок и коэффициентов преобразования интенсивности *)
  mask = Table[RandomSample[Join[ConstantArray[1, 4], ConstantArray[0, 4]]], {8}];
  inverseMask = 1 - mask;
  coefficients = {0.299, 0.587, 0.114};

  (* Создание CVZ из секретной строки secret *)
  CVZ = IntegerDigits[ToCharacterCode[secret, "WindowsCyrillic"], 2];
  Do[CVZ[[i]] = PadLeft[CVZ[[i]], 8], {i, 1, Length[CVZ]}];
  CVZ = Flatten[CVZ];

  (* Функция для извлечения данных из блока *)
  Bits = {};
  Do[AppendTo[Bits, 
    Module[{blockImageData, maskedPixels, inverseMaskedPixels, 
      luminanceMasked, luminanceInverseMasked, luminanceDifference, bit},
      blockImageData = ImageData[stegoBlocks[[i, j]], "Byte"];
      maskedPixels = Flatten[blockImageData*mask, 1];
      inverseMaskedPixels = Flatten[blockImageData*inverseMask, 1];
      luminanceMasked = Mean[maskedPixels . coefficients];
      luminanceInverseMasked = Mean[inverseMaskedPixels . coefficients];
      luminanceDifference = luminanceInverseMasked - luminanceMasked;
      bit = If[luminanceDifference > 0, 1, 0];
      bit]], 
  {i, Length[stegoBlocks]}, {j, Length[stegoBlocks[[1]]]}];

  (* Извлечение и проверка CVZ *)
  extractedCVZ = Take[Bits, Length[CVZ]];
  byteGroups = Partition[extractedCVZ, 8];
  byteValues = FromDigits[#, 2] & /@ byteGroups;
  decodedText = FromCharacterCode[byteValues, "WindowsCyrillic"];

  (* Вывод результатов проверки *)
  If[extractedCVZ == CVZ, 
    Print["ЦВЗ успешно встроен и извлечен: " <> decodedText], 
    Print["Ошибка: ЦВЗ не соответствует оригиналу"]];

  decodedText
];
```

